// Filter for next 14 days and extract basic info
const today = new Date();
const dateStart = new Date(today);
const dateEnd = new Date(today);
dateEnd.setDate(dateEnd.getDate() + 14);

const entries = $input.all();
const filtered = [];

for (const entry of entries) {
 const props = entry.json.properties;
 const dateProp = props?.Date?.date;

 if (!dateProp || !dateProp.start) continue;

 const entryDate = new Date(dateProp.start);
 const mappedDate = new Date(today.getFullYear(), entryDate.getMonth(), entryDate.getDate());

 if (mappedDate >= dateStart && mappedDate <= dateEnd) {
 filtered.push({
 json: {
 pageId: entry.json.id,
 name: props?.Name?.title?.map(t => t.plain_text).join('') || '',
 date: mappedDate.toISOString().split('T')[0],
 types: props?.['Email Type']?.multi_select?.map(s => s.name) || []
 }
 });
 }
}

return filtered;

const items = $input.all();

// Group blocks by page
const pageContents = {};

for (const item of items) {
 const block = item.json;
 const parentId = block.pageId || block.parent?.page_id;

 if (!parentId) continue;

 if (!pageContents[parentId]) {
 pageContents[parentId] = [];
 }

 const type = block.type;
 let text = '';

 if (type === 'paragraph') {
 text = block.paragraph?.rich_text?.map(t => t.plain_text).join('');
 } else if (type === 'bulleted_list_item') {
 text = '• ' + block.bulleted_list_item?.rich_text?.map(t => t.plain_text).join('');
 } else if (type === 'numbered_list_item') {
 text = block.numbered_list_item?.rich_text?.map(t => t.plain_text).join('');
 } else if (type === 'heading_1') {
 text = '## ' + block.heading_1?.rich_text?.map(t => t.plain_text).join('');
 } else if (type === 'heading_2') {
 text = '### ' + block.heading_2?.rich_text?.map(t => t.plain_text).join('');
 } else if (type === 'heading_3') {
 text = '#### ' + block.heading_3?.rich_text?.map(t => t.plain_text).join('');
 } else if (type === 'quote') {
 text = '> ' + block.quote?.rich_text?.map(t => t.plain_text).join('');
 } else if (type === 'callout') {
 text = '💡 ' + block.callout?.rich_text?.map(t => t.plain_text).join('');
 }

 if (text.trim()) {
 pageContents[parentId].push(text);
 }
}

// Get parent topic info from previous node
const topics = items
 .filter(i => i.json.pageId && !i.json.type)
 .map(i => i.json);

// If we don't have topic info, create from unique pageIds
const uniquePageIds = Object.keys(pageContents);
const result = uniquePageIds.map(pageId => {
 const topicInfo = topics.find(t => t.pageId === pageId) || { pageId, name: 'Unknown', date: '', types: [] };
 return {
 json: {
 ...topicInfo,
 contentLines: pageContents[pageId],
 fullContent: pageContents[pageId].join('\n')
 }
 };
});

return result;

const records = $input.all();

return records.map(r => ({
 json: {
 id: r.json.id,
 firmenname: r.json.fields?.Firmenname || '',
 klaviyoKey: r.json.fields?.['Klaviyo API Key'] || '',
 website: r.json.fields?.Website || '',
 branche: r.json.fields?.Branche || '',
 tonalitaet: r.json.fields?.Tonalität || '',
 emailFrom: r.json.fields?.['E-Mail Rechnungen'] || 'hello@adsdrop.de',
 type: 'client'
 }
})).filter(c => c.json.klaviyoKey);

// Mark topics
const topics = $input.all().map(t => ({
 json: { ...t.json, type: 'topic' }
}));
return topics;

const items = $input.all();

const topics = items.filter(i => i.json.type === 'topic');
const clients = items.filter(i => i.json.type === 'client');

if (topics.length === 0 || clients.length === 0) {
 throw new Error(`Missing: ${topics.length} topics, ${clients.length} clients`);
}

const combos = [];
for (const client of clients) {
 for (const topic of topics) {
 combos.push({
 json: {
 topic: topic.json,
 client: client.json
 }
 });
 }
}

return combos;

const item = $input.first().json;
const client = item.client;

if (!client.website) {
 return [{
 json: { ...item, websiteHtml: '', hasError: 'No website' }
 }];
}

try {
 const resp = await $httpRequest({
 method: 'GET',
 url: client.website,
 timeout: 10000
 });

 return [{
 json: { ...item, websiteHtml: resp.body || resp }
 }];
} catch (e) {
 return [{
 json: { ...item, websiteHtml: '', hasError: e.message }
 }];
}

