// Get Claude's response and extract data
const item = $input.first().json;
const claudeResponse = item.body;
const client = item.client;
const topic = item.topic;

// Parse Claude's analysis JSON
let analysis;
try {
  // Find JSON in Claude's response
  const content = claudeResponse.content[0].text;
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error("No JSON found in response");
  }
} catch (e) {
  // Fallback values if parsing fails
  analysis = {
    products: ["Produkte"],
    tone: "standard",
    usp: "Qualität und Service",
    mainColor: "#000000"
  };
}

// Use Claude's analysis for personalization
const mainProduct = analysis.products && analysis.products.length > 0 
  ? analysis.products[0] 
  : "Produkte";

const tone = analysis.tone || "standard";
const usp = analysis.usp || "Qualität und Service";
const mainColor = analysis.mainColor || "#000000";

// Build personalized content from Notion
const contentLines = topic.contentLines || [];
let contentHtml = '';

if (contentLines.length > 0) {
  contentHtml = contentLines.map(line => {
    // Replace generic terms with brand-specific
    const personalizedLine = line
      .replace(/Produkt/g, mainProduct)
      .replace(/deine Marke/g, client.firmenname);

    if (line.startsWith('• ')) {
      return `<li style="margin: 8px 0; line-height: 1.6;">${personalizedLine.substring(2)}</li>`;
    } else if (line.startsWith('## ')) {
      return `<h3 style="font-size: 20px; margin: 24px 0 12px 0; color: #111;">${personalizedLine.substring(3)}</h3>`;
    } else if (line.startsWith('### ')) {
      return `<h4 style="font-size: 18px; margin: 20px 0 10px 0; color: #222;">${personalizedLine.substring(4)}</h4>`;
    } else if (line.startsWith('> ')) {
      return `<blockquote style="border-left: 4px solid ${mainColor}; padding-left: 16px; margin: 20px 0; font-style: italic; color: #555;">${personalizedLine.substring(2)}</blockquote>`;
    } else if (line.startsWith('💡 ')) {
      return `<div style="background: #f8f8f8; padding: 16px; border-radius: 8px; margin: 16px 0; border-left: 3px solid ${mainColor};"><strong>Tipp:</strong> ${personalizedLine.substring(2)}</div>`;
    } else {
      return `<p style="line-height: 1.7; margin: 12px 0;">${personalizedLine}</p>`;
    }
  }).join('');
} else {
  contentHtml = `<p>Entdecke ${mainProduct} bei ${client.firmenname}.</p>
<p>Wir bieten ${usp} und freuen uns, dir unsere Produkte zu präsentieren.</p>`;
}

// Set greeting based on tone
let greeting;
if (tone === 'luxury') {
  greeting = `Willkommen in der Welt von ${client.firmenname}`;
} else if (tone === 'casual') {
  greeting = `Hey! Schön, dass du da bist`;
} else {
  greeting = `Hallo von ${client.firmenname}`;
}

// Return complete email data
return [{
  json: {
    ...item,
    claudeAnalysis: analysis,
    emailData: {
      greeting,
      subject: `${topic.name} | ${client.firmenname}`,
      previewText: `Neue ${mainProduct} entdecken`,
      contentHtml,
      cta: `${mainProduct} entdecken`,
      guarantee: analysis.usp?.toLowerCase().includes('versand') ? 'Kostenloser Versand' : '30 Tage Rückgabe',
      mainColor
    }
  }
}];

const item = $input.first().json;
const client = item.client;

try {
 const resp = await $httpRequest({
 method: 'GET',
 url: 'https://a.klaviyo.com/api/lists',
 headers: {
 'Authorization': `Klaviyo-API-Key ${client.klaviyoKey}`,
 'revision': '2024-10-15'
 }
 });

 const lists = resp.body?.data || [];
 let listId = lists[0]?.id;
 for (const l of lists) {
 const n = l.attributes?.name?.toLowerCase() || '';
 if (n.includes('newsletter') || n.includes('main')) {
 listId = l.id;
 break;
 }
 }

 return [{
 json: { ...item, targetList: listId }
 }];
} catch (e) {
 return [{
 json: { ...item, targetList: null, error: e.message }
 }];
}

const item = $input.first().json;
const client = item.client;
const topic = item.topic;
const subject = item.subject;
const listId = item.targetList;

const topicDate = topic.date;
const today = new Date();
let sendDate;

if (topicDate) {
 const d = new Date(topicDate);
 sendDate = d < today ? new Date(d.setDate(d.getDate() + 7)) : d;
} else {
 sendDate = new Date(today.setDate(today.getDate() + 1));
}

const sendAt = sendDate.toISOString().split('T')[0] + 'T09:00:00.000Z';

const body = {
 data: {
 type: 'campaign',
 attributes: {
 name: subject,
 audiences: { included: listId ? [listId] : [] },
 send_strategy: { method: 'static', options_static: { datetime: sendAt } },
 'campaign-messages': {
 data: [{
 type: 'campaign-message',
 attributes: {
 channel: 'email',
 label: subject.slice(0, 50),
 content: { subject: subject, preview_text: item.emailData?.previewText || '' }
 }
 }]
 }
 }
 }
};

try {
 const resp = await $httpRequest({
 method: 'POST',
 url: 'https://a.klaviyo.com/api/campaigns',
 headers: {
 'Authorization': `Klaviyo-API-Key ${client.klaviyoKey}`,
 'revision': '2024-10-15',
 'Content-Type': 'application/json'
 },
 body: body
 });

 return [{
 json: {
 client: client,
 topic: topic,
 subject: subject,
 campaignId: resp.body?.data?.id,
 status: 'Created',
 adminUrl: resp.body?.data?.id ? `https://www.klaviyo.com/campaign/${resp.body.data.id}/edit` : null
 }
 }];
} catch (e) {
 return [{
 json: {
 client: client,
 topic: topic,
 subject: subject,
 campaignId: null,
 status: 'Failed',
 error: e.message
 }
 }];
}

const results = $input.all();
const campaigns = results.map(r => r.json);

const success = campaigns.filter(c => c.campaignId).length;
const failed = campaigns.length - success;

const summary = {};
for (const c of campaigns) {
 const name = c.client?.firmenname || 'Unknown';
 if (!summary[name]) summary[name] = 0;
 if (c.campaignId) summary[name]++;
}

return [{
 json: {
 success,
 failed,
 total: campaigns.length,
 summary,
 date: new Date().toLocaleDateString('de-DE'),
 campaignLinks: campaigns.filter(c => c.adminUrl).map(c => `• [${c.client.firmenname} - ${c.topic.name}](${c.adminUrl})`) 
 }
}];
